text:
太阳系由太阳引力主导，八大行星沿椭圆轨道公转，距离越近公转速度越快（开普勒第三定律）。内行星（水星到火星）轨道紧凑，外行星（木星到海王星）轨道宽阔，周期从88天到165年不等。

```show-widget
{"title": "solar_system_3d", "widget_code": "<style>
canvas { display: block; width: 100% !important; height: 420px !important; }
#controls { display: flex; align-items: center; gap: 12px; padding: 10px 0 0; font-size: 13px; color: var(--color-text-secondary); flex-wrap: wrap; }
</style>
<canvas id="c"></canvas>
<div id="controls">
  <label style="display:flex;align-items:center;gap:8px;flex:1;min-width:160px">
    速度 <input type="range" min="1" max="20" value="5" step="1" style="flex:1" oninput="speedMul=this.value*0.4">
  </label>
  <button onclick="setView('top')">俯视</button>
  <button onclick="setView('side')">侧视</button>
  <button onclick="setView('front')">斜视</button>
</div>
<script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js" onload="init()"></script>
<script>
var scene, camera, renderer, controls;
var speedMul = 2.0;
function init() {
  if (!window.THREE || !THREE.OrbitControls) return;
  var canvas = document.getElementById('c');
  var W = canvas.clientWidth, H = 420;
  renderer = new THREE.WebGLRenderer({ canvas: canvas, antialias: true, alpha: true });
  renderer.setSize(W, H);
  renderer.setPixelRatio(Math.min(devicePixelRatio, 2));
  scene = new THREE.Scene();
  camera = new THREE.PerspectiveCamera(45, W / H, 0.1, 1000);
  camera.position.set(0, 18, 36);
  scene.add(new THREE.AmbientLight(0xffffff, 0.35));
  var sun = new THREE.DirectionalLight(0xffffff, 1.0);
  sun.position.set(0, 5, 0);
  scene.add(sun);
  controls = new THREE.OrbitControls(camera, canvas);
  controls.enableDamping = true;
  controls.dampingFactor = 0.08;
  controls.autoRotate = false;
  var t = 0;
  function animate() {
    requestAnimationFrame(animate);
    t += 0.005 * speedMul;
    planets.forEach(function(p) {
      p.mesh.position.x = Math.cos(t * p.speed) * p.r;
      p.mesh.position.z = Math.sin(t * p.speed) * p.r;
      p.mesh.rotation.y += 0.02;
    });
    sunMesh.rotation.y += 0.004;
    controls.update();
    renderer.render(scene, camera);
  }
  animate();
}
if (window.THREE && THREE.OrbitControls) init();

var sunMesh = (function() {
  var geo = new THREE.SphereGeometry(2.2, 32, 24);
  var mat = new THREE.MeshBasicMaterial({ color: 0xEF9F27 });
  var mesh = new THREE.Mesh(geo, mat);
  mesh.name = '太阳';
  scene.add(mesh);
  var glow = new THREE.Mesh(
    new THREE.SphereGeometry(2.5, 32, 24),
    new THREE.MeshBasicMaterial({ color: 0xFAC775, transparent: true, opacity: 0.18 })
  );
  scene.add(glow);
  return mesh;
})();

var planetData = [
  { name: '水星', r: 4.2,  size: 0.28, color: 0xB4B2A9, speed: 4.15,  tilt: 0.03 },
  { name: '金星', r: 5.8,  size: 0.45, color: 0xFAC775, speed: 1.62,  tilt: 0.05 },
  { name: '地球', r: 7.6,  size: 0.50, color: 0x378ADD, speed: 1.00,  tilt: 0.41 },
  { name: '火星', r: 9.6,  size: 0.35, color: 0xD85A30, speed: 0.53,  tilt: 0.44 },
  { name: '木星', r: 13.5, size: 1.10, color: 0xEF9F27, speed: 0.084, tilt: 0.05 },
  { name: '土星', r: 17.5, size: 0.90, color: 0xFAEDA, speed: 0.034, tilt: 0.47 },
  { name: '天王星',r: 21.0, size: 0.65, color: 0x9FE1CB, speed: 0.012, tilt: 1.71 },
  { name: '海王星',r: 24.5, size: 0.60, color: 0x185FA5, speed: 0.006, tilt: 0.49 }
];

var planets = planetData.map(function(d) {
  var geo = new THREE.SphereGeometry(d.size, 24, 16);
  var mat = new THREE.MeshLambertMaterial({ color: d.color });
  var mesh = new THREE.Mesh(geo, mat);
  mesh.name = d.name;
  mesh.rotation.z = d.tilt;
  scene.add(mesh);

  var ringGeo = new THREE.RingGeometry(d.r - 0.02, d.r + 0.02, 96);
  var ringMat = new THREE.MeshBasicMaterial({ color: 0x888780, side: THREE.DoubleSide, transparent: true, opacity: 0.25 });
  var ring = new THREE.Mesh(ringGeo, ringMat);
  ring.rotation.x = Math.PI / 2;
  scene.add(ring);

  if (d.name === '土星') {
    var sRingGeo = new THREE.RingGeometry(1.3, 2.2, 64);
    var sRingMat = new THREE.MeshBasicMaterial({ color: 0xFAC775, side: THREE.DoubleSide, transparent: true, opacity: 0.55 });
    var sRing = new THREE.Mesh(sRingGeo, sRingMat);
    sRing.rotation.x = 1.1;
    mesh.add(sRing);
  }

  return { mesh: mesh, r: d.r, speed: d.speed, name: d.name };
});

var raycaster = new THREE.Raycaster();
var mouse = new THREE.Vector2();
var dragDist = 0, startX, startY;
var canvas = document.getElementById('c');
canvas.addEventListener('mousedown', function(e) { startX = e.clientX; startY = e.clientY; dragDist = 0; });
canvas.addEventListener('mousemove', function(e) { dragDist += Math.abs(e.clientX - startX) + Math.abs(e.clientY - startY); });
canvas.addEventListener('click', function(e) {
  if (dragDist > 5) return;
  var rect = canvas.getBoundingClientRect();
  mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
  mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;
  raycaster.setFromCamera(mouse, camera);
  var targets = planets.map(function(p) { return p.mesh; });
  targets.push(sunMesh);
  var hits = raycaster.intersectObjects(targets);
  if (hits.length) {
    window.__widgetSendMessage('详细介绍太阳系中的' + hits[0].object.name + '，包括其物理特征和有趣事实');
  }
});

function setView(v) {
  var pos = { top: [0, 40, 0.1], side: [40, 4, 0], front: [0, 18, 36] }[v];
  camera.position.set(pos[0], pos[1], pos[2]);
  camera.lookAt(0, 0, 0);
  controls.update();
}
</script>"}
```

点击任意行星或太阳可以深入了解它的详细信息。拖拽旋转视角，滚轮缩放，顶部控制栏可切换视角和调节公转速度。土星的光环也做了还原，木星体积最大，水星公转最快——这些都符合真实的相对比例关系。
